VALUES
  ('promotion-4c199b1b-moex-00012', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '有關給付遲延之效力，下列敘述何者正確？', '["遲延後之給付，於債權人無利益者，債權人得拒絕其給付", "債權人不得請求賠償遲延所生之損害", "債務人在遲延中，對於不可抗力所生之損害，無庸負責", "縱不可歸責於債務人事由致給付遲延，債務人仍負遲延責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00013', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '有關物之瑕疵擔保，下列何者正確？', '["買受人於契約成立時，知其物有瑕疵者，縱無特約，出賣人仍負擔保之責", "買受人欠缺善良管理人之注意，而不知有瑕疵者，出賣人如未保證其無瑕疵時，依法不負擔保 之責", "物之出賣人，原則上應擔保其物於締約時無滅失或減少其價值之瑕疵", "種類之物買賣，如其物有瑕疵，若契約未另有約定，買受人得不解除契約或請求減少價金，而 即時請求另行交付無瑕疵之物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00014', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '承攬人關於工作物之瑕疵修補請求權時效規定，下列何者正確？', '["非建築物或土地上之工作物，如其瑕疵自工作交付後經過1年始發見者，定作人不得主張", "建築物之重大修繕者，瑕疵修補請求權時效，為15年", "承攬人故意不告知其建築物之瑕疵者，瑕疵修補請求權時效，延為20年", "瑕疵修補請求權時效，不得以特約延長"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00015', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '有關合夥，下列敘述何者正確？', '["合夥人受有報酬執行合夥之事務，應盡與處理自己事務為同一注意", "執行合夥事務之合夥人，非經其他合夥人過半數之同意，不得將其解任", "分配損益之成數，未經約定者，按照各合夥人出資額之比例定之", "合夥之決算及分配利益，除契約另有訂定外，應於每年會計年度終了後6個月內為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00016', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '有關添附，下列敘述何者正確？', '["利用債權概念，解決當事人間所有權歸屬紛爭", "動產因附合成為不動產之重要成分，動產所有權消滅", "多數在來米和少數蓬來米混合時，應由二物之所有權人共有混合物之所有權", "加工於自己的材料，亦有加工規定之適用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00017', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '有關占有被侵奪，下列敘述何者錯誤？', '["侵奪發生後，占有人得主張自力取回權，向加害人取回占有物", "出租人無故進入承租人承租之房屋者，承租人得主張己力防禦權，予以驅逐", "在地上權人占有之土地上架設騰空的天線，地上權人可以對其主張占有妨害除去請求權", "A誤認B之占有物為己有，而以和平手段取走占有物時，B不得向A主張占有物返還請求權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00018', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '甲將電腦送交乙店修理，修畢後，甲未償還修理費，卻向乙請求返還電腦。下列敘述何者錯誤？', '["乙對甲有給付修理費之請求權", "甲未償還修理費前，乙得留置該電腦拒絕返還", "債權未屆清償期，乙仍得主張留置權", "符合民法第936條要件時，乙得將電腦變價，用以清償修理費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00019', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '有關意定監護，下列敘述何者正確？', '["謂本人與受任人約定，於本人受輔助宣告時，受任人允為擔任監護人之契約", "意定監護契約之訂立或變更，應由法院作成判決書始為成立", "法院為監護之宣告時，受監護宣告之人已訂有意定監護契約者，應以意定監護契約所定之受任 人為監護人", "法院為監護之宣告後，受任人有正當理由者，得經本人同意，聲請法院許可辭任其職務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00020', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '有關喪失其繼承權之實務見解，下列何者正確？', '["被繼承人終年臥病在床，繼承人無正當理由，始終不予探視者，致被繼承人精神上莫大痛苦， 尚非屬重大虐待之行為，不足以構成喪失繼承權", "對於被繼承人有重大之虐待或侮辱情事，經被繼承人表示其不得繼承者，喪失繼承權", "對之負有扶養義務而惡意不予扶養，不足以構成喪失繼承權", "故意致應繼承人於死，而未致死，因而受刑之宣告者。經被繼承人宥恕者，其繼承權不喪失"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL),
  ('promotion-4c199b1b-moex-00021', 'promotion-4c199b1b', 'promotion-4c199b1b-moex-114-9b7ab1bb', 'sub-promotion-4c199b1b-01', NULL, 'single_choice', '媽媽A看到餐桌上有一盒糕餅，以為是家人買的，很自然地吃光它。後來才知道那盒糕餅是女兒 H的家教老師B隨手借放在該處。下列敘述何者錯誤？', '["A可能成立侵權行為", "A可能成立無因管理", "A可能成立不當得利", "A可以事後和B訂立契約，解決本事件"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:16+00:00", "source_pdf_sha1": "90a3a0e73e71", "answer_pdf_sha1": "af2e32916fff", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "401", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "消費者保護"}'::jsonb, NULL)
